export default function App() {
  const [tab, setTab] = useState("home");
  const [rounds, setRounds] = useState(initialRounds);
  const [golfers, setGolfers] = useState(initialGolfers);
  const [posts, setPosts] = useState([]);
  const [stories, setStories] = useState([]);
  const [dataLoaded, setDataLoaded] = useState(false);
  const [myName, setMyName] = useState(null); // null until loaded from personal storage or entered
  const [nameLoaded, setNameLoaded] = useState(false);
  const [viewedStoryIds, setViewedStoryIds] = useState([]);
  const [showLogForm, setShowLogForm] = useState(false);
  const [showGhinModal, setShowGhinModal] = useState(false);
  const [ghinStatus, setGhinStatus] = useState("disconnected"); // disconnected | connected
  const [ghinNumber, setGhinNumber] = useState("");
  const [ghinHandicap, setGhinHandicap] = useState("");
  const [maxDistance, setMaxDistance] = useState(10);
  const [handSpread, setHandSpread] = useState(6);
  const [requested, setRequested] = useState({});
  const [inbox, setInbox] = useState(seedInbox);
  const [showInbox, setShowInbox] = useState(false);
  const [storyViewer, setStoryViewer] = useState(null); // { list, index }
  const [showComposer, setShowComposer] = useState(false);
  const [commentsFor, setCommentsFor] = useState(null); // postId

  const myInitials = initialsOf(myName);

  // Load identity + shared feed data once on mount.
  useEffect(() => {
    const savedName = loadPersonal(STORAGE_KEYS.name, null);
    if (savedName) setMyName(savedName);
    setNameLoaded(true);

    const savedViewed = loadPersonal(STORAGE_KEYS.viewed, []);
    setViewedStoryIds(savedViewed);

    (async () => {
      const loadedPosts = await loadShared(STORAGE_KEYS.posts, null);
      if (loadedPosts) {
        setPosts(loadedPosts);
      } else {
        setPosts(seedPosts);
        saveShared(STORAGE_KEYS.posts, seedPosts);
      }

      const loadedStories = await loadShared(STORAGE_KEYS.stories, null);
      if (loadedStories) {
        setStories(loadedStories);
      } else {
        setStories(seedStories);
        saveShared(STORAGE_KEYS.stories, seedStories);
      }

      setDataLoaded(true);
    })();
  }, []);

  // Poll the shared feed every few seconds so everyone testing this on their
  // own phone sees new posts/likes/comments/stories show up without a manual
  // refresh. (Supabase also supports true real-time push if you want to
  // upgrade this later — see README.md.)
  useEffect(() => {
    if (!dataLoaded) return;
    const interval = setInterval(async () => {
      const freshPosts = await loadShared(STORAGE_KEYS.posts, null);
      if (freshPosts) setPosts(freshPosts);
      const freshStories = await loadShared(STORAGE_KEYS.stories, null);
      if (freshStories) setStories(freshStories);
    }, 5000);
    return () => clearInterval(interval);
  }, [dataLoaded]);

  function saveMyName(name) {
    const trimmed = name.trim();
    if (!trimmed) return;
    setMyName(trimmed);
    savePersonal(STORAGE_KEYS.name, trimmed);
  }

  function updatePosts(updater) {
    setPosts((prev) => {
      const next = updater(prev);
      saveShared(STORAGE_KEYS.posts, next);
      return next;
    });
  }

  function updateStories(updater) {
    setStories((prev) => {
      const next = updater(prev);
      saveShared(STORAGE_KEYS.stories, next);
      return next;
    });
  }

  const sortedRounds = useMemo(
    () => [...rounds].sort((a, b) => new Date(a.date) - new Date(b.date)),
    [rounds]
  );

  const diffs = sortedRounds.map((r) => differential(r.score, r.rating, r.slope));
  const currentHandicap = handicapFromDiffs(diffs);
  const avgScore = rounds.length ? Math.round(rounds.reduce((a, r) => a + r.score, 0) / rounds.length) : null;
  const bestRound = rounds.length ? Math.min(...rounds.map((r) => r.score)) : null;

  const trendData = sortedRounds.map((r, i) => {
    const upTo = diffs.slice(0, i + 1);
    return { date: fmtDate(r.date), hcp: handicapFromDiffs(upTo) };
  });

  function logRound(course, score, rating, slope, meta) {
    const id = Date.now();
    const today = new Date().toISOString().slice(0, 10);
    const r = { id, date: today, course, score: Number(score), rating: Number(rating), slope: Number(slope), method: meta?.method, holes: meta?.holes };
    setRounds((prev) => [...prev, r]);
    if (meta?.shareToFeed) {
      updatePosts((prev) => [
        {
          id: "round-" + id,
          kind: "round",
          author: myName,
          initials: myInitials,
          round: r,
          time: new Date().toISOString(),
          likes: 0,
          liked: false,
          images: meta?.images || [],
          text: meta?.caption || "",
          comments: [],
        },
        ...prev,
      ]);
    }
    setShowLogForm(false);
  }

  function addPost(kind, text, images) {
    const id = "post-" + Date.now();
    updatePosts((prev) => [
      { id, kind, author: myName, initials: myInitials, text, time: new Date().toISOString(), likes: 0, liked: false, images: images || [], comments: [] },
      ...prev,
    ]);
    setShowComposer(false);
  }

  function toggleLike(id) {
    updatePosts((prev) =>
      prev.map((p) => (p.id === id ? { ...p, liked: !p.liked, likes: p.liked ? p.likes - 1 : p.likes + 1 } : p))
    );
  }

  function deletePost(id) {
    updatePosts((prev) => prev.filter((p) => p.id !== id));
  }

  function addComment(postId, text) {
    if (!text.trim()) return;
    updatePosts((prev) =>
      prev.map((p) =>
        p.id === postId
          ? { ...p, comments: [...p.comments, { id: "c-" + Date.now(), author: myName, text: text.trim() }] }
          : p
      )
    );
  }

  function addMyStory(imageSrc) {
    const story = { id: "story-" + Date.now(), name: myName, initials: myInitials, image: imageSrc, time: new Date().toISOString() };
    updateStories((prev) => [story, ...prev]);
  }

  function markStoriesViewed(ids) {
    setViewedStoryIds((prev) => {
      const next = Array.from(new Set([...prev, ...ids]));
      savePersonal(STORAGE_KEYS.viewed, next);
      return next;
    });
  }

  function openStoryGroup(list, index) {
    setStoryViewer({ list, index });
    markStoriesViewed([list[index].id]);
  }

  function advanceStory(dir) {
    setStoryViewer((prev) => {
      if (!prev) return prev;
      const nextIndex = prev.index + dir;
      if (nextIndex < 0 || nextIndex >= prev.list.length) return null;
      markStoriesViewed([prev.list[nextIndex].id]);
      return { ...prev, index: nextIndex };
    });
  }

  function toggleRequest(id) {
    setRequested((prev) => ({ ...prev, [id]: !prev[id] }));
  }

  function respondToInbox(reqId, accept) {
    setInbox((prev) => prev.map((r) => (r.id === reqId ? { ...r, status: accept ? "accepted" : "declined" } : r)));
    if (accept) {
      const req = inbox.find((r) => r.id === reqId);
      const g = golfers.find((g) => g.id === req?.golferId);
      if (g) {
        updatePosts((prev) => [
          {
            id: "match-" + reqId,
            kind: "note",
            author: myName,
            initials: myInitials,
            text: `Match confirmed with ${g.name}. See you on the course!`,
            time: new Date().toISOString(),
            likes: 0,
            liked: false,
            images: [],
            comments: [],
          },
          ...prev,
        ]);
      }
    }
  }

  function connectGhin(number, handicap) {
    setGhinNumber(number.trim());
    setGhinHandicap(handicap.trim());
    setGhinStatus("connected");
    setShowGhinModal(false);
  }

  const roundPar = 72; // fixed display par for score-to-par labeling

  const filteredGolfers = golfers.filter((g) => {
    const withinDistance = g.distance <= maxDistance;
    const withinHandicap = currentHandicap == null || Math.abs(g.handicap - currentHandicap) <= handSpread;
    return withinDistance && withinHandicap;
  });

  const feedPosts = [...posts].sort((a, b) => new Date(b.time) - new Date(a.time));

  const pendingCount = inbox.filter((r) => r.status === "pending").length;

  if (!dataLoaded) {
    return (
      <div style={{ ...styles.app, alignItems: "center", justifyContent: "center" }}>
        <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
        <div style={styles.loadingSpinner} />
      </div>
    );
  }

  if (!myName) {
    return <NameGate onSubmit={saveMyName} />;
  }

  return (
    <div style={styles.app}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@600;700;800&family=Inter:wght@400;500;600&family=JetBrains+Mono:wght@500;700&display=swap');
        * { box-sizing: border-box; }
        button { font-family: inherit; cursor: pointer; }
        input { font-family: inherit; }
        ::-webkit-scrollbar { display: none; }
        @keyframes spin { to { transform: rotate(360deg); } }
        @keyframes storyfill { from { width: 0%; } to { width: 100%; } }
      `}</style>

      <header style={styles.header}>
        <div style={styles.headerTexture} />
        <div style={styles.headerRow}>
          <div style={styles.wordmarkFlag}>
            <Flag size={16} color="#14342B" strokeWidth={2.8} />
          </div>
          <span style={styles.wordmark}>STICK TALK</span>
          <div style={{ flex: 1 }} />
          <button style={styles.inboxBtn} onClick={() => setShowInbox(true)}>
            <Inbox size={19} color="#EDE6D6" />
            {pendingCount > 0 && <span style={styles.inboxBadge}>{pendingCount}</span>}
          </button>
        </div>
        <span style={styles.headerSub}>
          {tab === "home" && "Clubhouse feed"}
          {tab === "match" && "Find a match"}
          {tab === "gps" && "On-course GPS"}
          {tab === "profile" && "Your profile & settings"}
        </span>
      </header>

      <main style={styles.main}>
        {tab === "home" && (
          <HomeTab
            posts={feedPosts}
            onLike={toggleLike}
            onDelete={deletePost}
            myName={myName}
            myInitials={myInitials}
            stories={stories}
            viewedStoryIds={viewedStoryIds}
            onOpenStory={openStoryGroup}
            onAddMyStory={addMyStory}
            onOpenComposer={() => setShowComposer(true)}
            onOpenComments={(postId) => setCommentsFor(postId)}
          />
        )}
        {tab === "match" && (
          <MatchTab
            golfers={filteredGolfers}
            maxDistance={maxDistance}
            setMaxDistance={setMaxDistance}
            handSpread={handSpread}
            setHandSpread={setHandSpread}
            requested={requested}
            toggleRequest={toggleRequest}
            currentHandicap={currentHandicap}
          />
        )}
        {tab === "gps" && <GpsTab />}
        {tab === "profile" && (
          <ProfileTab
            myName={myName}
            myInitials={myInitials}
            currentHandicap={currentHandicap}
            avgScore={avgScore}
            bestRound={bestRound}
            roundsCount={rounds.length}
            ghinStatus={ghinStatus}
            ghinNumber={ghinNumber}
            ghinHandicap={ghinHandicap}
            onConnectGhin={() => setShowGhinModal(true)}
          />
        )}
      </main>

      <nav style={styles.nav}>
        <NavBtn icon={HomeIcon} label="Home" active={tab === "home"} onClick={() => setTab("home")} />
        <NavBtn icon={Users} label="Matches" active={tab === "match"} onClick={() => setTab("match")} />
        <CenterNavBtn onClick={() => setShowLogForm(true)} />
        <NavBtn icon={Navigation} label="GPS" active={tab === "gps"} onClick={() => setTab("gps")} />
        <NavBtn icon={User} label="Profile" active={tab === "profile"} onClick={() => setTab("profile")} />
      </nav>

      {showLogForm && (
        <LogRoundModal onClose={() => setShowLogForm(false)} onSubmit={logRound} />
      )}

      {showGhinModal && (
        <GhinModal
          initialNumber={ghinNumber}
          initialHandicap={ghinHandicap}
          onClose={() => setShowGhinModal(false)}
          onSave={connectGhin}
        />
      )}

      {showInbox && (
        <InboxModal
          inbox={inbox}
          golfers={golfers}
          onClose={() => setShowInbox(false)}
          onRespond={respondToInbox}
        />
      )}

      {storyViewer && (
        <StoryViewer
          list={storyViewer.list}
          index={storyViewer.index}
          onClose={() => setStoryViewer(null)}
          onAdvance={advanceStory}
        />
      )}

      {showComposer && <ComposerModal onClose={() => setShowComposer(false)} onSubmit={addPost} />}

      {commentsFor && (
        <CommentsModal
          post={posts.find((p) => p.id === commentsFor)}
          onClose={() => setCommentsFor(null)}
          onAddComment={(text) => addComment(commentsFor, text)}
        />
      )}
    </div>
  );
}

