function ScoreBadge({ score, par }) {
  const rel = score - par;
  const label = rel === 0 ? "E" : rel > 0 ? `+${rel}` : `${rel}`;
  const color = rel <= 0 ? "#74C69D" : rel <= 8 ? "#EDE6D6" : "#C1443A";
  return (
    <div style={{ ...styles.scoreBadge, borderColor: color }}>
      <span style={{ ...styles.scoreBadgeNum, color }}>{score}</span>
      <span style={styles.scoreBadgeRel}>{label}</span>
    </div>
  );
}

