function StoriesBar({ stories, myName, myInitials, viewedStoryIds, onOpenStory, onAddMyStory }) {
  const fileRef = useRef(null);
  const [uploading, setUploading] = useState(false);

  // Group the shared story list by author so each person gets one ring,
  // even if they've posted several stories today.
  const groups = useMemo(() => {
    const map = new Map();
    for (const s of stories) {
      if (!map.has(s.name)) map.set(s.name, []);
      map.get(s.name).push(s);
    }
    for (const arr of map.values()) arr.sort((a, b) => new Date(a.time) - new Date(b.time));
    return map;
  }, [stories]);

  const mine = groups.get(myName) || [];
  const others = [...groups.entries()].filter(([name]) => name !== myName);

  async function handleFile(e) {
    const file = e.target.files?.[0];
    e.target.value = "";
    if (!file) return;
    setUploading(true);
    try {
      const dataUrl = await fileToSharedImage(file);
      onAddMyStory(dataUrl);
    } catch (err) {
      // ignore — upload failed, user can retry
    }
    setUploading(false);
  }

  return (
    <div style={styles.storiesRow}>
      <input ref={fileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleFile} />

      <div style={styles.storyItem}>
        <button
          style={styles.storyAvatarWrap}
          onClick={() => (mine.length ? onOpenStory(mine, 0) : fileRef.current?.click())}
        >
          <div
            style={{
              ...styles.storyRing,
              background: mine.length
                ? mine.every((s) => viewedStoryIds.includes(s.id))
                  ? "#2D6A4F"
                  : "linear-gradient(135deg, #74C69D, #F4A261)"
                : "transparent",
              border: mine.length ? "none" : "1.5px dashed #2D6A4F",
            }}
          >
            {mine.length ? (
              <div style={styles.storyThumbClip}>
                <PhotoTile src={mine[mine.length - 1].image} style={{ width: "100%", height: "100%", borderRadius: "50%" }} />
              </div>
            ) : (
              <div style={styles.avatarSm}>{uploading ? "…" : myInitials}</div>
            )}
          </div>
          <button style={styles.storyAddBadge} onClick={(e) => { e.stopPropagation(); fileRef.current?.click(); }}>
            <Plus size={11} color="#14342B" strokeWidth={3} />
          </button>
        </button>
        <span style={styles.storyLabel}>Your story</span>
      </div>

      {others.map(([name, arr]) => {
        const latest = arr[arr.length - 1];
        const allViewed = arr.every((s) => viewedStoryIds.includes(s.id));
        return (
          <div key={name} style={styles.storyItem}>
            <button style={styles.storyAvatarWrap} onClick={() => onOpenStory(arr, 0)}>
              <div
                style={{
                  ...styles.storyRing,
                  background: allViewed ? "#2D6A4F" : "linear-gradient(135deg, #74C69D, #F4A261)",
                }}
              >
                <div style={styles.storyThumbClip}>
                  <PhotoTile src={latest.image} style={{ width: "100%", height: "100%", borderRadius: "50%" }} />
                </div>
              </div>
            </button>
            <span style={styles.storyLabel}>{name.split(" ")[0]}</span>
          </div>
        );
      })}
    </div>
  );
}

function StoryViewer({ list, index, onClose, onAdvance }) {
  const story = list[index];
  useEffect(() => {
    const t = setTimeout(() => onAdvance(1), 4500);
    return () => clearTimeout(t);
  }, [index]);

  if (!story) return null;

  return (
    <div style={styles.storyOverlay}>
      <div style={styles.storyProgressRow}>
        {list.map((_, i) => (
          <div key={i} style={styles.storyProgressTrack}>
            <div
              key={i === index ? `${i}-${index}-active` : i}
              style={{
                ...styles.storyProgressFill,
                width: i < index ? "100%" : "0%",
                animation: i === index ? "storyfill 4.5s linear forwards" : "none",
              }}
            />
          </div>
        ))}
      </div>

      <div style={styles.storyHeadRow}>
        <div style={styles.avatarSm}>{story.initials || story.name?.[0]}</div>
        <span style={styles.storyHeadName}>{story.name}</span>
        <div style={{ flex: 1 }} />
        <button style={styles.iconBtn} onClick={onClose}>
          <X size={20} color="#EDE6D6" />
        </button>
      </div>

      <PhotoTile src={story.image} style={{ flex: 1, width: "100%", borderRadius: 16 }} />

      <div style={styles.storyTapZones}>
        <button style={styles.storyTapZone} onClick={() => onAdvance(-1)} aria-label="Previous story" />
        <button style={styles.storyTapZone} onClick={() => onAdvance(1)} aria-label="Next story" />
      </div>
    </div>
  );
}

function PostCard({ post: p, onLike, onOpenComments, onDelete, myName }) {
  const [menuOpen, setMenuOpen] = useState(false);
  const kindMeta = {
    round: { label: null },
    practice: { label: "Practice session", icon: Dumbbell },
    note: { label: null },
  };
  const meta = kindMeta[p.kind] || {};
  const previewComments = p.comments.slice(-2);
  const isMine = p.author === myName;

  return (
    <div style={styles.card}>
      <div style={styles.cardTopRow}>
        <div style={styles.avatarSm}>{p.initials || p.author?.slice(0, 2).toUpperCase()}</div>
        <div style={{ flex: 1 }}>
          <div style={styles.cardName}>{p.author}</div>
          <div style={styles.cardMeta}>
            {p.kind === "round" ? (
              <>
                <MapPin size={12} color="#8FA396" /> {p.round.course} · {timeAgo(p.time)}
              </>
            ) : (
              <>{meta.label ? `${meta.label} · ` : ""}{timeAgo(p.time)}</>
            )}
          </div>
        </div>
        {isMine && (
          <div style={{ position: "relative" }}>
            <button style={styles.kebabBtn} onClick={() => setMenuOpen((o) => !o)}>
              <MoreHorizontal size={18} color="#5C7268" />
            </button>
            {menuOpen && (
              <>
                <button style={styles.menuBackdrop} onClick={() => setMenuOpen(false)} aria-label="Close menu" />
                <div style={styles.postMenu}>
                  <button
                    style={styles.postMenuDeleteItem}
                    onClick={() => {
                      setMenuOpen(false);
                      onDelete(p.id);
                    }}
                  >
                    <Trash2 size={14} color="#C1443A" /> Delete post
                  </button>
                </div>
              </>
            )}
          </div>
        )}
        {!isMine && <MoreHorizontal size={18} color="#5C7268" />}
      </div>

      {p.text && <div style={styles.noteText}>{p.text}</div>}

      {p.kind === "round" && (
        <div style={styles.postScorecardWrap}>
          <Scorecard round={p.round} />
        </div>
      )}

      {p.images && p.images.length > 0 && (
        <div style={styles.postImageWrap}>
          <PhotoTile src={p.images[0]} style={{ width: "100%", height: 210, borderRadius: 12 }} />
        </div>
      )}

      <div style={styles.cardActions}>
        <button style={styles.actionBtn} onClick={() => onLike(p.id)}>
          <Heart size={16} color={p.liked ? "#C1443A" : "#8FA396"} fill={p.liked ? "#C1443A" : "none"} />
          {p.likes}
        </button>
        <button style={styles.actionBtn} onClick={() => onOpenComments(p.id)}>
          <MessageCircle size={16} color="#8FA396" />
          {p.comments.length}
        </button>
      </div>

      {previewComments.length > 0 && (
        <div style={styles.commentPreviewWrap}>
          {previewComments.map((c) => (
            <div key={c.id} style={styles.commentPreviewLine}>
              <span style={styles.commentPreviewAuthor}>{c.author}</span> {c.text}
            </div>
          ))}
          {p.comments.length > 2 && (
            <button style={styles.viewAllComments} onClick={() => onOpenComments(p.id)}>
              View all {p.comments.length} comments
            </button>
          )}
        </div>
      )}
    </div>
  );
}

function ComposerModal({ onClose, onSubmit }) {
  const [text, setText] = useState("");
  const [image, setImage] = useState(null);
  const [uploading, setUploading] = useState(false);
  const fileRef = useRef(null);

  async function handleFile(e) {
    const file = e.target.files?.[0];
    e.target.value = "";
    if (!file) return;
    setUploading(true);
    try {
      setImage(await fileToSharedImage(file));
    } catch (err) {
      // ignore — upload failed, user can retry
    }
    setUploading(false);
  }

  const canPost = text.trim().length > 0 || image;

  return (
    <div style={styles.modalOverlay} onClick={onClose}>
      <div style={styles.modal} onClick={(e) => e.stopPropagation()}>
        <div style={styles.modalHead}>
          <span style={styles.modalTitle}>Share an update</span>
          <button style={styles.iconBtn} onClick={onClose}>
            <X size={18} color="#EDE6D6" />
          </button>
        </div>

        <textarea
          style={styles.composerTextarea}
          placeholder="What's happening out there?"
          value={text}
          onChange={(e) => setText(e.target.value)}
          rows={4}
        />

        <input ref={fileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleFile} />

        {image ? (
          <div style={styles.composerImageWrap}>
            <PhotoTile src={image} style={{ width: "100%", height: 160, borderRadius: 10 }} />
            <button style={styles.composerImageRemove} onClick={() => setImage(null)}>
              <Trash2 size={14} color="#EDE6D6" />
            </button>
          </div>
        ) : (
          <button style={styles.addPhotoBtn} onClick={() => fileRef.current?.click()} disabled={uploading}>
            <Camera size={16} color="#74C69D" /> {uploading ? "Uploading…" : "Add a photo"}
          </button>
        )}

        <button
          style={{ ...styles.logBtn, marginBottom: 0, opacity: canPost ? 1 : 0.5 }}
          disabled={!canPost}
          onClick={() => onSubmit("note", text, image ? [image] : [])}
        >
          Post
        </button>
      </div>
    </div>
  );
}

function CommentsModal({ post, onClose, onAddComment }) {
  const [text, setText] = useState("");
  if (!post) return null;

  function submit() {
    if (!text.trim()) return;
    onAddComment(text);
    setText("");
  }

  return (
    <div style={styles.modalOverlay} onClick={onClose}>
      <div style={{ ...styles.modal, maxHeight: "78vh", display: "flex", flexDirection: "column" }} onClick={(e) => e.stopPropagation()}>
        <div style={styles.modalHead}>
          <span style={styles.modalTitle}>Comments</span>
          <button style={styles.iconBtn} onClick={onClose}>
            <X size={18} color="#EDE6D6" />
          </button>
        </div>

        <div style={{ overflowY: "auto", flex: 1, marginBottom: 12 }}>
          {post.comments.length === 0 && (
            <div style={styles.empty}>
              <p style={styles.emptyTitle}>No comments yet</p>
              <p style={styles.emptyBody}>Be the first to say something.</p>
            </div>
          )}
          {post.comments.map((c) => (
            <div key={c.id} style={styles.commentRow}>
              <div style={styles.avatarSm}>{c.author.slice(0, 2).toUpperCase()}</div>
              <div style={{ flex: 1 }}>
                <div style={styles.cardName}>{c.author}</div>
                <div style={styles.noteText}>{c.text}</div>
              </div>
            </div>
          ))}
        </div>

        <div style={styles.commentInputRow}>
          <input
            style={{ ...styles.input, flex: 1, marginTop: 0 }}
            placeholder="Add a comment…"
            value={text}
            onChange={(e) => setText(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && submit()}
          />
          <button style={styles.commentSendBtn} onClick={submit} disabled={!text.trim()}>
            <Send size={16} color="#14342B" />
          </button>
        </div>
      </div>
    </div>
  );
}

